Spawn.Code:
void main(in    float age,
          in    float invLifetime,
          inout float2 pos,
          inout float2 dir,
          inout float  scale,
          inout float2 vel,
          inout float  spin,
          inout float4 color,
          in    float  t) {
  float r = t;
  vel.x = 50 + (30 * r);
  r = (r * 7) % 1;
  vel.y = (r * 20) - 10;
  r = (r * 11) % 1;
}

Update.Code:
void main(in    float age,
          in    float invLifetime,
          inout float2 pos,
          inout float2 dir,
          inout float  scale,
          inout float2 vel,
          inout float  spin,
          inout float4 color,
          in    float  t) {
  color.r = age;
  color.g = 1 - age;
  scale = 0.5 + (0.5 * age);
}
